def img_to_data_url(rel_path: str) -> str:
    """Convert a local image file to a base64 data URL. Returns empty string if file not found."""
    if not rel_path:
        return ""
    p = ROOT / rel_path
    if not p.exists():
        return ""
    mime = mimetypes.guess_type(str(p))[0] or "image/jpeg"
    data = base64.b64encode(p.read_bytes()).decode()
    return f"data:{mime};base64,{data}"
